// src/pages/Dashboard.js
import React, { useEffect, useRef, useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { useNavigate } from 'react-router-dom';
import { gsap } from 'gsap';
import { useAuth } from '../hooks/useAuth';
import api from '../services/api';
import { FaParking, FaCar, FaCheckCircle, FaChartBar, FaClock, FaFire } from 'react-icons/fa';

function CountdownTimer({ checkIn, durationHours }) {
  const [remaining, setRemaining] = useState('');
  useEffect(() => {
    const end = new Date(checkIn).getTime() + durationHours * 3600000;
    const tick = () => {
      const diff = end - Date.now();
      if (diff <= 0) { setRemaining('Expired'); return; }
      const h = Math.floor(diff / 3600000);
      const m = Math.floor((diff % 3600000) / 60000);
      const s = Math.floor((diff % 60000) / 1000);
      setRemaining(`${h}h ${String(m).padStart(2,'0')}m ${String(s).padStart(2,'0')}s`);
    };
    tick();
    const id = setInterval(tick, 1000);
    return () => clearInterval(id);
  }, [checkIn, durationHours]);
  return (
    <div style={{ display:'flex', alignItems:'center', gap:8, padding:'8px 12px', borderRadius:12, background:'rgba(0,210,255,0.06)' }}>
      <FaClock size={14} /> <span style={{ fontWeight:700 }}>{remaining}</span>
    </div>
  );
}

function OccupancyHeatmap() {
  const hours = Array.from({ length: 24 }, (_, i) => i);
  const heat = hours.map(h => {
    if (h >= 7 && h <= 9) return 0.85;
    if (h >= 12 && h <= 14) return 0.75;
    if (h >= 17 && h <= 19) return 0.9;
    return 0.25 + Math.random() * 0.3;
  });
  const color = (v) => v >= 0.8 ? '#ef4444' : v >= 0.6 ? '#f59e0b' : v >= 0.3 ? '#3b82f6' : '#10b981';
  return (
    <div style={{ display:'flex', flexDirection:'column', gap:8 }}>
      <div style={{ display:'flex', gap:8, alignItems:'flex-end', height:100 }}>
        {heat.map((v,i) => (
          <div key={i} style={{ flex:1, height:`${v*100}%`, background: color(v), borderRadius:6, transition:'height .4s' }} />
        ))}
      </div>
      <div style={{ display:'flex', justifyContent:'space-between', fontSize:12, color:'var(--text-muted)' }}>
        <span>12am</span><span>6am</span><span>12pm</span><span>6pm</span><span>11pm</span>
      </div>
    </div>
  );
}

export default function Dashboard() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const ref = useRef(null);

  const { data: slots = [], isLoading } = useQuery({
    queryKey: ['slots'],
    queryFn: () => api.get('/slots').then(r => r.data),
    refetchInterval: 15000,
  });

  const { data: bookings = [] } = useQuery({
    queryKey: ['bookings'],
    queryFn: () => api.get('/bookings').then(r => r.data),
    enabled: !!user,
  });

  useEffect(() => {
    if (!ref.current || isLoading) return;
    gsap.fromTo(ref.current.querySelectorAll('.dash-anim'), { y: 18, opacity: 0 }, { y: 0, opacity: 1, duration: 0.5, stagger: 0.06 });
  }, [isLoading]);

  const available = slots.filter(s => s.status === 'AVAILABLE').length;
  const occupied = slots.filter(s => s.status === 'OCCUPIED').length;
  const reserved = slots.filter(s => s.status === 'RESERVED').length;
  const total = slots.length || 1;
  const occupancyPct = Math.round((occupied / total) * 100);

  const STATS = [
    { label: 'Available', value: available, icon: <FaCheckCircle/>, cls: 'green' },
    { label: 'Occupied', value: occupied, icon: <FaCar/>, cls: 'red' },
    { label: 'Reserved', value: reserved, icon: <FaParking/>, cls: 'yellow' },
    { label: 'Total Slots', value: total, icon: <FaChartBar/>, cls: 'primary' },
  ];

  if (isLoading) return <div style={{ minHeight: '60vh', display:'flex', alignItems:'center', justifyContent:'center' }}><div className="suprs-spinner" /></div>;

  return (
    <div className="page page-dashboard" ref={ref}>
      <div className="dashboard-shell">
        <main className="dashboard-main">
          <div className="dash-anim" style={{ marginBottom: 18 }}>
            <h1>👋 Welcome back, <span className="text-gradient">{user?.name || (user?.email||'User').split('@')[0]}</span></h1>
            <p style={{ marginTop:6, color:'var(--text-muted)' }}>{new Date().toLocaleDateString()}</p>
          </div>

          {/* Live Parking Map */}
          <div className="dash-anim glass-card" style={{ padding:'1.25rem', marginBottom: 22 }}>
            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', gap:12 }}>
              <h4 style={{ margin:0 }}>🅿️ Live Parking Map</h4>
              <button className="btn-suprs" onClick={() => navigate('/booking')}>+ Book a Slot</button>
            </div>

            <div style={{ marginTop: 12 }}>
              {slots.length === 0 ? (
                <div style={{ padding: 28, borderRadius: 12, background: 'rgba(255,255,255,0.02)', color:'var(--text-muted)' }}>
                  No slots configured yet. Ask an admin to add slots.
                </div>
              ) : (
                <div className="parking-grid" style={{ marginTop: 6 }}>
                  {slots.map(slot => {
                    const st = (slot.status || 'AVAILABLE').toLowerCase();
                    return (
                      <div key={slot.id} className={`slot-box ${st}`} onClick={() => st === 'available' && navigate('/booking')}>
                        <div style={{ display:'flex', justifyContent:'space-between', width:'100%' }}>
                          <div className="slot-number">{slot.slot_number}</div>
                          <div className={`slot-status-badge ${st}`}>{slot.status}</div>
                        </div>
                        <div style={{ textAlign:'center', color:'var(--text-muted)', fontSize:13 }}>{slot.lot_name || slot.location || ''}</div>
                        <div style={{ display:'flex', justifyContent:'space-between', width:'100%', alignItems:'center' }}>
                          <div style={{ fontSize:13, color:'var(--text-muted)' }}>${slot.price_per_hour || 0}/hr</div>
                          <div style={{ fontSize:11, color:'var(--text-muted)' }}>{slot.occupant_email ? slot.occupant_email.split('@')[0] : ''}</div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          </div>
        </main>

        <aside className="dashboard-side">
          <div className="dash-anim" style={{ marginBottom: 14 }}>
            <div style={{ display:'grid', gridTemplateColumns:'repeat(2,1fr)', gap:12 }}>
              {STATS.map(s => (
                <div key={s.label} className={`stat-card ${s.cls}`} style={{ minHeight:120 }}>
                  <div className="stat-icon" style={{ background: 'rgba(255,255,255,0.02)' }}>{s.icon}</div>
                  <div>
                    <div className="stat-value">{s.value}</div>
                    <div className="stat-label">{s.label}</div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="dash-anim glass-card" style={{ marginBottom: 16, padding:'1.25rem' }}>
            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center' }}>
              <h5 style={{ margin:0, fontSize:14 }}>🔥 Occupancy Rate</h5>
              <div style={{ fontWeight:900 }}>{occupancyPct}%</div>
            </div>
            <div style={{ marginTop:10 }}>
              <div className="progress-bar-track"><div className="progress-bar-fill" style={{ width: `${occupancyPct}%`, background: occupancyPct>=80 ? '#ef4444' : occupancyPct>=50 ? '#f59e0b' : '#10b981' }} /></div>
              <div style={{ display:'flex', justifyContent:'space-between', marginTop:10, fontSize:12, color:'var(--text-muted)' }}>
                <span>{available} available</span><span>{occupied} occupied</span>
              </div>
            </div>
          </div>

          <div className="dash-anim glass-card heatmap-card" style={{ padding:'1.25rem' }}>
            <h5 style={{ margin:0, marginBottom:8 }}>🔥 Hourly Demand Heatmap</h5>
            <OccupancyHeatmap />
          </div>
        </aside>
      </div>
    </div>
  );
}